/* media data comes from assets/media-data.js (window.MEDIA), generated by build_media.py.
   Shape: MEDIA[slug] = { name, cover, collections:[{ label, slug, images:[], videos:[{src,poster}] }] } */
const MEDIA = window.MEDIA || {};
const cover       = (slug) => (MEDIA[slug] && MEDIA[slug].cover) || `assets/img/${slug}/cover.jpg`;
const collections = (slug) => (MEDIA[slug] && MEDIA[slug].collections) || [];
const allImages   = (slug) => collections(slug).flatMap(c => c.images);
const allVideos   = (slug) => collections(slug).flatMap(c => c.videos);

