/* ============================================================
   RENDER
   ============================================================ */
const el = (html) => { const t = document.createElement('template'); t.innerHTML = html.trim(); return t.content.firstElementChild; };

/* -- Work / masonry: interleave brands so the gallery mixes work -- */
const workGrid = document.getElementById('workGrid');

// Each brand contributes a spread of photo teaser tiles (videos live in the modal gallery).
// A brand can set `teaser` (a collection slug) to source its grid tiles from a specific
// campaign — handy for brands whose full set is graphics-heavy.
// GRID_TILES weights how many tiles each brand gets: lead with the strongest imagery.
const GRID_TILES = {
  'north-kiteboarding': 8,
  'north-foils': 8,
  'surf-life-saving-nz': 9,
  'surfr-app': 5,
  'bike-storage': 2,
};
const piles = CASES.map((c, ci) => {
  // explicit hand-picked grid imagery wins (strongest shots, no weak auto-samples)
  if (c.gridImages && c.gridImages.length) return c.gridImages.map(src => ({ ci, src }));
  let imgs = allImages(c.slug);
  if (c.teaser) {
    const col = collections(c.slug).find(x => x.slug === c.teaser);
    if (col && col.images.length) imgs = col.images;
  }
  // evenly sample images across the set so the teaser feels representative
  const want = Math.min(GRID_TILES[c.slug] || 5, imgs.length);
  const step = Math.max(1, Math.floor(imgs.length / want));
  const picks = [];
  for (let i = 0, n = 0; i < imgs.length && n < want; i += step, n++) picks.push({ ci, src: imgs[i] });
  return picks.slice(0, want);
});
// round-robin interleave so the grid mixes brands like a contact sheet
const maxLen = Math.max(...piles.map(p => p.length));
const tiles = [];
for (let k = 0; k < maxLen; k++) piles.forEach(p => { if (p[k]) tiles.push(p[k]); });

tiles.forEach(t => {
  const c = CASES[t.ci];
  const headline = c.metrics[0];
  workGrid.appendChild(el(`
    <button class="tile reveal" data-case="${t.ci}" aria-label="Open case study: ${c.name}">
      <span class="tile__rest">${c.name}</span>
      <div class="tile__media">
        <img class="tile__img" src="${t.src}" alt="${c.name} social content" loading="lazy" />
      </div>
      <div class="tile__cap">
        <div class="tile__tag">${c.tag.split('·')[0].trim()}</div>
        <div class="tile__name">${c.name}</div>
        <div class="tile__metric"><b>${headline[0]}</b> ${headline[1]}</div>
      </div>
    </button>`));
});

