/* carousel scroll controls (buttons + drag) */
const postsCarousel = document.getElementById('postsCarousel');
const scrollByCards = (dir) => {
  const card = postsTrack.querySelector('.post');
  const amount = card ? (card.offsetWidth + 16) * 1.5 : 360;
  postsCarousel.scrollBy({ left: dir * amount, behavior: 'smooth' });
};
document.getElementById('postsPrev').addEventListener('click', () => scrollByCards(-1));
document.getElementById('postsNext').addEventListener('click', () => scrollByCards(1));
// drag-to-scroll (pointer), without hijacking card clicks
let dragX = 0, dragL = 0, dragging = false, moved = false;
postsCarousel.addEventListener('pointerdown', e => { dragging = true; moved = false; dragX = e.pageX; dragL = postsCarousel.scrollLeft; });
postsCarousel.addEventListener('pointermove', e => {
  if (!dragging) return;
  const dx = e.pageX - dragX;
  if (Math.abs(dx) > 6) moved = true;
  postsCarousel.scrollLeft = dragL - dx;
});
const endDrag = () => { dragging = false; };
postsCarousel.addEventListener('pointerup', endDrag);
postsCarousel.addEventListener('pointerleave', endDrag);
// suppress the click that follows a drag so it doesn't open Instagram accidentally
postsCarousel.addEventListener('click', e => { if (moved) { e.preventDefault(); moved = false; } }, true);

/* ============================================================
   CASE STUDY MODAL (with image gallery)
   ============================================================ */
const modal = document.getElementById('modal');
const mHero = document.getElementById('mHero');
let lastFocused = null;
let currentCollections = [];   // [{label, items:[{type,src,poster}]}] for the open brand
let galleryItems = [];         // the items the lightbox is currently navigating

function openCase(i){
  const c = CASES[i];
  lastFocused = document.activeElement;
  mHero.style.backgroundImage = `linear-gradient(180deg, transparent 50%, rgba(0,0,0,.6)), url("${c.banner || cover(c.slug)}")`;
  mHero.style.backgroundPosition = c.bannerPos || 'center';
  document.getElementById('mBadge').textContent = c.badge;
  document.getElementById('mRole').textContent = c.role;
  document.getElementById('mTitle').textContent = c.name;
  document.getElementById('mChallenge').textContent = c.challenge;
  document.getElementById('mWork').textContent = c.work;

  const mm = document.getElementById('mMetrics');
  mm.innerHTML = '';
  c.metrics.forEach(([v, l]) => {
    const node = el(`<div class="mstat"><div class="v"><span></span></div><div class="l">${l}</div></div>`);
    mm.appendChild(node);
    countUpText(node.querySelector('.v span'), v);   // count-up each metric on open
  });

  // Build campaign collections; each becomes a labelled, lightbox-scoped sub-gallery
  currentCollections = collections(c.slug).map(col => ({
    label: col.label,
    items: [
      ...col.videos.map(v => ({ type: 'video', src: v.src, poster: v.poster })),
      ...col.images.map(src => ({ type: 'image', src }))
    ]
  })).filter(col => col.items.length);

  const mg = document.getElementById('mGallery');
  mg.innerHTML = '';
  currentCollections.forEach((col, colIdx) => {
    const nImg = col.items.filter(i => i.type === 'image').length;
    const nVid = col.items.length - nImg;
    const count = [nImg && `${nImg} photo${nImg > 1 ? 's' : ''}`, nVid && `${nVid} video${nVid > 1 ? 's' : ''}`].filter(Boolean).join(' · ');
    const section = el(`
      <section class="collection">
        <div class="gallery-head"><h4>${col.label}</h4><span class="cnt">${count}</span></div>
        <div class="modal__gallery"></div>
      </section>`);
    const grid = section.querySelector('.modal__gallery');
    col.items.forEach((it, gi) => {
      const thumb = it.type === 'video' ? it.poster : it.src;
      grid.appendChild(el(`
        <button class="gitem ${it.type === 'video' ? 'gitem--video' : ''}" data-col="${colIdx}" data-gi="${gi}" aria-label="View ${it.type}">
          <img src="${thumb}" alt="${c.name}, ${col.label} ${it.type}" loading="lazy" />
        </button>`));
    });
    mg.appendChild(section);
  });

  modal.classList.add('open');
  modal.setAttribute('aria-hidden', 'false');
  document.body.style.overflow = 'hidden';
  modal.querySelector('.modal__panel').scrollTop = 0;
  modal.querySelector('.modal__close').focus();
}
function closeCase(){
  modal.classList.remove('open');
  modal.setAttribute('aria-hidden', 'true');
  document.body.style.overflow = '';
  if (lastFocused) lastFocused.focus();
}
workGrid.addEventListener('click', e => {
  const t = e.target.closest('[data-case]');
  if (t) openCase(+t.dataset.case);
});
modal.addEventListener('click', e => { if (e.target.hasAttribute('data-close')) closeCase(); });
document.addEventListener('keydown', e => { if (e.key === 'Escape' && modal.classList.contains('open') && !lightbox.classList.contains('open')) closeCase(); });

// open lightbox from a gallery thumbnail - scoped to its campaign collection
document.getElementById('mGallery').addEventListener('click', e => {
  const b = e.target.closest('[data-gi]');
  if (!b) return;
  const col = currentCollections[+b.dataset.col];
  if (!col) return;
  galleryItems = col.items;
  openLightbox(+b.dataset.gi);
});

/* ============================================================
   LIGHTBOX - images + video playback, prev/next, keyboard
   ============================================================ */
const lightbox = document.getElementById('lightbox');
const lbStage = document.getElementById('lbStage');
const lbCount = document.getElementById('lbCount');
let lbIndex = 0;

function renderLB(){
  const it = galleryItems[lbIndex];
  if (!it) return;
  lbStage.innerHTML = it.type === 'video'
    ? `<video src="${it.src}" poster="${it.poster}" controls autoplay playsinline></video>`
    : `<img src="${it.src}" alt="Gallery item ${lbIndex + 1}" />`;
  lbCount.textContent = `${lbIndex + 1} / ${galleryItems.length}`;
}
function openLightbox(i){
  if (!galleryItems.length) return;
  lbIndex = (i + galleryItems.length) % galleryItems.length;
  renderLB();
  lightbox.classList.add('open');
  lightbox.setAttribute('aria-hidden', 'false');
}
function closeLightbox(){
  lightbox.classList.remove('open');
  lightbox.setAttribute('aria-hidden', 'true');
  lbStage.innerHTML = '';   // stop any playing video
}
function stepLB(d){ openLightbox(lbIndex + d); }

lightbox.addEventListener('click', e => {
  if (e.target.hasAttribute('data-lb-close') || e.target === lightbox) return closeLightbox();
  if (e.target.closest('[data-lb-prev]')) return stepLB(-1);
  if (e.target.closest('[data-lb-next]')) return stepLB(1);
});
document.addEventListener('keydown', e => {
  if (!lightbox.classList.contains('open')) return;
  if (e.key === 'Escape') closeLightbox();
  else if (e.key === 'ArrowLeft') stepLB(-1);
  else if (e.key === 'ArrowRight') stepLB(1);
});

/* ============================================================
   NAV - scrolled state + mobile toggle
   ============================================================ */
const nav = document.getElementById('nav');
const onScroll = () => {
  nav.classList.toggle('scrolled', window.scrollY > 24);
  document.getElementById('toTop').classList.toggle('show', window.scrollY > 600);
};
window.addEventListener('scroll', onScroll, { passive: true });
onScroll();

const navLinks = document.getElementById('navLinks');
const navToggle = document.getElementById('navToggle');
navToggle.addEventListener('click', () => {
  const open = navLinks.classList.toggle('open');
  navToggle.setAttribute('aria-expanded', open);
});
navLinks.addEventListener('click', e => { if (e.target.tagName === 'A') navLinks.classList.remove('open'); });

document.getElementById('toTop').addEventListener('click', () =>
  window.scrollTo({ top: 0, behavior: 'smooth' }));

/* ============================================================
   REVEAL ON SCROLL
   ============================================================ */
const io = new IntersectionObserver((entries) => {
  entries.forEach(en => { if (en.isIntersecting){ en.target.classList.add('in'); io.unobserve(en.target); } });
}, { threshold: 0.12, rootMargin: '0px 0px -40px 0px' });
document.querySelectorAll('.reveal').forEach(n => io.observe(n));

/* ============================================================
   CONTACT FORM (demo - no backend yet)
   ============================================================ */
const form = document.getElementById('contactForm');
form.addEventListener('submit', e => {
  e.preventDefault();
  const note = document.getElementById('formNote');
  if (!form.checkValidity()) { note.textContent = 'Please fill in all fields.'; note.style.color = 'var(--sunline)'; return; }
  note.textContent = 'Thanks. This is a demo, so connect a form backend to actually receive it.';
  note.style.color = 'var(--surf)';
  form.reset();
});

document.getElementById('year').textContent = new Date().getFullYear();

/* ============================================================
   HERO PARALLAX + STATS COUNT-UP (subtle scroll animation)
   ============================================================ */
const reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

/* -- Faint scroll-progress accent across the top -- */
const scrollProgress = document.getElementById('scrollProgress');
if (scrollProgress) {
  const updateProgress = () => {
    const docH = document.documentElement.scrollHeight - window.innerHeight;
    scrollProgress.style.transform = `scaleX(${docH > 0 ? window.scrollY / docH : 0})`;
  };
  window.addEventListener('scroll', updateProgress, { passive: true });
  window.addEventListener('resize', updateProgress, { passive: true });
  updateProgress();
}

/* -- Generic count-up: animates the last number in a string, keeping decimals,
      thousands separators and any surrounding text (e.g. "76K→80K", "£310K", "+5,000"). -- */
function countUpText(elTarget, finalStr, dur = 1400){
  const tokens = String(finalStr).match(/[\d,]*\.?\d+/g);
  if (reduceMotion || !tokens) { elTarget.textContent = finalStr; return; }
  const token = tokens[tokens.length - 1];
  const idx = String(finalStr).lastIndexOf(token);
  const pre = String(finalStr).slice(0, idx);
  const suf = String(finalStr).slice(idx + token.length);
  const hasComma = token.includes(',');
  const decimals = token.includes('.') ? token.split('.')[1].length : 0;
  const target = parseFloat(token.replace(/,/g, ''));
  const fmt = (v) => hasComma
    ? Number(v.toFixed(decimals)).toLocaleString('en-US', { minimumFractionDigits: decimals, maximumFractionDigits: decimals })
    : v.toFixed(decimals);
  const start = performance.now();
  const stepFn = (now) => {
    const p = Math.min(1, (now - start) / dur);
    const eased = 1 - Math.pow(1 - p, 3);
    elTarget.textContent = pre + fmt(target * eased) + suf;
    if (p < 1) requestAnimationFrame(stepFn);
  };
  requestAnimationFrame(stepFn);
}

/* -- Hero parallax: waves, glow and headline drift/fade at different rates -- */
if (!reduceMotion) {
  const hero       = document.querySelector('.hero');
  const heroWaves  = document.querySelector('.hero__waves');
  const heroGlow   = document.querySelector('.hero__glow');
  const heroInner  = document.querySelector('.hero .wrap');
  let parking = false;
  const parallax = () => {
    const y = window.scrollY;
    const h = hero.offsetHeight || 1;
    if (y <= h) {
      const p = y / h;
      if (heroWaves) heroWaves.style.transform = `translate3d(0, ${y * 0.28}px, 0)`;
      if (heroGlow)  heroGlow.style.transform  = `translate3d(0, ${y * 0.16}px, 0)`;
      if (heroInner) {
        heroInner.style.transform = `translate3d(0, ${y * 0.18}px, 0)`;
        heroInner.style.opacity = String(Math.max(0, 1 - p * 1.05));
      }
    }
    parking = false;
  };
  window.addEventListener('scroll', () => {
    if (!parking) { requestAnimationFrame(parallax); parking = true; }
  }, { passive: true });
  parallax();
}

/* -- Stats count-up when the strip scrolls into view -- */
function countUp(elTarget){
  const to  = parseInt(elTarget.dataset.to, 10);
  const pre = elTarget.dataset.prefix || '';
  const suf = elTarget.dataset.suffix || '';
  const render = (v) => {
    elTarget.innerHTML = (pre ? `<span>${pre}</span>` : '') + v + (suf ? `<span>${suf}</span>` : '');
  };
  if (reduceMotion) { render(to); return; }
  const dur = 1500, start = performance.now();
  const step = (now) => {
    const p = Math.min(1, (now - start) / dur);
    const eased = 1 - Math.pow(1 - p, 3);   // easeOutCubic
    render(Math.round(to * eased));
    if (p < 1) requestAnimationFrame(step);
  };
  requestAnimationFrame(step);
}

const statsEl = document.getElementById('stats');
if (statsEl) {
  const statNums = statsEl.querySelectorAll('.num[data-to]');
  const statObserver = new IntersectionObserver((entries, obs) => {
    entries.forEach(en => {
      if (en.isIntersecting) { statNums.forEach(countUp); obs.disconnect(); }
    });
  }, { threshold: 0.4 });
  statObserver.observe(statsEl);
}

/* Graceful fallback: if any thumbnail fails to load, hide its tile/item
   rather than showing a broken-image icon. */
document.addEventListener('error', e => {
  const img = e.target;
  if (img.tagName !== 'IMG') return;
  const host = img.closest('.tile, .gitem');
  if (host) host.style.display = 'none';
}, true);
